SELECT qd.* FROM queue_data qd
INNER JOIN (
SELECT restaurant_name, MAX(stat_time) as max_stat_time
FROM queue_data
WHERE 1=1

    AND location = #{location}


    AND category = #{category}


    AND restaurant_name = #{restaurantName}


    AND DATE_FORMAT(stat_time, '%Y-%m-%d %H:00:00') = DATE_FORMAT(#{statTime}, '%Y-%m-%d %H:00:00')

GROUP BY restaurant_name
) latest ON qd.restaurant_name = latest.restaurant_name
AND qd.stat_time = latest.max_stat_time
WHERE 1=1

    AND qd.location = #{location}


    AND qd.category = #{category}


    AND qd.restaurant_name = #{restaurantName}


    AND DATE_FORMAT(qd.stat_time, '%Y-%m-%d %H:00:00') = DATE_FORMAT(#{statTime}, '%Y-%m-%d %H:00:00')

ORDER BY qd.stat_time DESC

SELECT queue_number FROM queue_data
WHERE restaurant_name = #{restaurantName}
  AND stat_time < #{statTime}
ORDER BY stat_time DESC
    LIMIT 1

SELECT * FROM queue_data
WHERE restaurant_name = #{restaurantName}

    AND location = #{location}


    AND category = #{category}

ORDER BY stat_time DESC

SELECT DISTINCT location FROM queue_data WHERE 1=1
AND category = #{category}
AND restaurant_name = #{restaurantName}

SELECT DISTINCT restaurant_name FROM queue_data WHERE 1=1
AND location = #{location}
AND category = #{category}
AND restaurant_name = #{restaurantName}

SELECT * FROM queue_data

    
        AND location = #{location}
    
    
        AND category = #{category}
    
    
        AND restaurant_name = #{restaurantName}
    
    AND stat_time BETWEEN #{startTime} AND #{endTime}

ORDER BY restaurant_name, stat_time
